function addDynamicLights(surf: Surface): void {
  const smax = (surf.extents[0] >> 4) + 1;
  const tmax = (surf.extents[1] >> 4) + 1;

  for (let lnum = 0; lnum < MAX_DLIGHTS; lnum++) {
    if (!(surf.dlightBits & (1 << lnum))) continue; // not lit by this light
    const rad = clDlights[lnum].radius;
    const dist = dotProduct(clDlights[lnum].origin, surf.plane.normal) - surf.plane.dist;
    const minlight = rad - Math.abs(dist);
    if (minlight < clDlights[lnum].minlight) continue;
    for (let t = 0; t < tmax; t++) {
      for (let s = 0; s < smax; s++) {
        const sd = Math.abs(localImpact[0] - s * 16);
        const td = Math.abs(localImpact[1] - t * 16);
        const d = sd > td ? sd + (td >> 1) : td + (sd >> 1);
        if (d < minlight) blocklights[t * smax + s] += (rad - d) * 256;
      }
    }
  }
}
